<?php use App\Core\Helpers as H;use App\Services\EmailCampaignService;?><section class="panel"><h1><?=H::e($campaign['subject'])?></h1><p>Status: <strong><?=H::e($campaign['status'])?></strong> · Audience: <?=H::e(EmailCampaignService::audienceLabel($campaign['audience']))?></p><div class="email-preview"><p><?=nl2br(H::e($campaign['body']))?></p><?php if($campaign['cta_url']):?><a href="<?=H::e($campaign['cta_url'])?>"><?=H::e($campaign['cta_label'])?></a><?php endif;?></div><p>Queued <?=(int)($counts['queued']??0)?> · Sent <?=(int)($counts['sent']??0)?> · Failed <?=(int)($counts['failed']??0)?> · Suppressed <?=(int)($counts['suppressed']??0)?> · Cancelled <?=(int)($counts['cancelled']??0)?> · Remaining <?=(int)($counts['remaining']??0)?></p><form method="post" class="admin-actions"><input type="hidden" name="_csrf" value="<?=H::csrf()?>"><?php if($campaign['status']==='draft'):?><button name="action" value="queue">Queue</button><?php endif;?><?php if(in_array($campaign['status'],['draft','queued','sending'],true)):?><button name="action" value="cancel">Cancel unsent</button><?php endif;?><input type="email" name="test_email" placeholder="Active admin email"><button name="action" value="test">Send test</button></form><h2>Recipients</h2><?php if(!$recipients):?><p class="muted">No campaign recipients were selected.</p><?php else:?><div class="table-scroll"><table><thead><tr><th>Email</th><th>Name</th><th>Status</th><th>Last error</th></tr></thead><tbody><?php foreach($recipients as $r):?><tr><td><?=H::e($r['email'])?></td><td><?=H::e($r['name'])?></td><td><?=H::e($r['status'])?></td><td><?=H::e($r['last_error'])?></td></tr><?php endforeach;?></tbody></table></div><?php endif;?></section>
